// Extract and validate webhook input
const items = $input.all();
const body = items[0].json.body || items[0].json;
const source = (body.source || 'coingecko').toLowerCase().trim();
const contract_address = (body.contract_address || '').trim();
const chain = (body.chain || 'ethereum').toLowerCase().trim();
const run_id = (body.run_id || '').trim();
if (!contract_address) { throw new Error('Missing required field: contract_address'); }
return [{ json: { source, contract_address, chain, run_id, analysis_date: new Date().toISOString() } }];

// Parse CoinGecko response
const input = $('Extract Input').item.json;
const d = $input.all()[0].json;
try {
  const ticker = (d.symbol || '').toUpperCase();
  const name = d.name || '';
  const website = (d.links && d.links.homepage && d.links.homepage[0]) || '';
  const md = d.market_data || {};
  return [{ json: { ...input, ticker, name, website, categories: (d.categories || []).join(', '), market_cap: md.market_cap ? (md.market_cap.usd || 0) : 0, fdv: md.fully_diluted_valuation ? (md.fully_diluted_valuation.usd || 0) : 0, volume_24h: md.total_volume ? (md.total_volume.usd || 0) : 0, price: md.current_price ? (md.current_price.usd || 0) : 0, price_change_24h: md.price_change_percentage_24h || 0, price_change_7d: md.price_change_percentage_7d || 0, dex_liquidity_usd: 0, dex_buys_24h: 0, dex_sells_24h: 0, dex_liquidity_pct: 0, data_source: 'coingecko' } }];
} catch (e) { return [{ json: { ...input, ticker: '', name: '', parse_error: e.message, data_source: 'coingecko', market_cap: 0, fdv: 0, volume_24h: 0, price: 0, price_change_24h: 0, price_change_7d: 0 } }]; }

// Parse DexScreener response
const input = $('Extract Input').item.json;
const d = $input.all()[0].json;
try {
  const pairs = d.pairs || [];
  const chain = input.chain;
  const filtered = pairs.filter(p => (p.chainId || '').toLowerCase().includes(chain) && (p.volume ? p.volume.h24 : 0) > 1000);
  const best = filtered.sort((a, b) => ((b.volume ? b.volume.h24 : 0) || 0) - ((a.volume ? a.volume.h24 : 0) || 0))[0] || pairs[0];
  if (!best) return [{ json: { ...input, ticker: '', name: '', parse_error: 'No pairs', data_source: 'dexscreener', market_cap: 0, fdv: 0, volume_24h: 0, price: 0, price_change_24h: 0, price_change_7d: 0 } }];
  const bt = best.baseToken || {};
  const liq = best.liquidity ? (best.liquidity.usd || 0) : 0;
  const mc = best.marketCap || 0;
  return [{ json: { ...input, ticker: (bt.symbol || '').toUpperCase(), name: bt.name || '', website: '', categories: '', market_cap: mc, fdv: best.fdv || 0, volume_24h: best.volume ? (best.volume.h24 || 0) : 0, price: parseFloat(best.priceUsd || '0'), price_change_24h: best.priceChange ? (best.priceChange.h24 || 0) : 0, price_change_7d: 0, dex_liquidity_usd: liq, dex_buys_24h: best.txns && best.txns.h24 ? best.txns.h24.buys || 0 : 0, dex_sells_24h: best.txns && best.txns.h24 ? best.txns.h24.sells || 0 : 0, dex_liquidity_pct: mc > 0 ? (liq / mc * 100) : 0, data_source: 'dexscreener' } }];
} catch (e) { return [{ json: { ...input, ticker: '', name: '', parse_error: e.message, data_source: 'dexscreener', market_cap: 0, fdv: 0, volume_24h: 0, price: 0, price_change_24h: 0, price_change_7d: 0 } }]; }

// Build fundamentals research prompt
const d = $input.all()[0].json;
const prompt = `You are a crypto research analyst. Analyze this token:
- Ticker: ${d.ticker}
- Name: ${d.name}
- Chain: ${d.chain}
- Contract: ${d.contract_address}
- Price: $${d.price}
- Market Cap: $${d.market_cap}
- FDV: $${d.fdv}
- 24h Volume: $${d.volume_24h}

Cover: Narrative Positioning, Project Fundamentals, Team & Backers, Value Capture, Traction & Usage, Tokenomics & Unlocks, Roadmap & Catalysts, Competitive Analysis.
Be specific and data-driven.`;
return [{ json: { requestBody: { model: 'anthropic/claude-sonnet-4-5', messages: [{ role: 'user', content: prompt }], max_tokens: 4000 } } }];

// Build social research prompt
const d = $input.all()[0].json;
const prompt = `You are a crypto social intelligence analyst. Analyze social signals for:
- Ticker: ${d.ticker}
- Name: ${d.name}
- Chain: ${d.chain}
- Price: $${d.price}
- Market Cap: $${d.market_cap}

Cover: Attention Metrics, Account Analysis, KOL Signals, Sentiment Analysis, Community Coordination, Divergence Check, Narrative Heat.`;
return [{ json: { requestBody: { model: 'anthropic/claude-sonnet-4-5', messages: [{ role: 'user', content: prompt }], max_tokens: 3000 } } }];

// Combine research outputs
const items = $input.all();
let tokenData = {};
try { tokenData = $('Parse CoinGecko').first().json; } catch(e) {}
if (!tokenData || !tokenData.ticker) { try { tokenData = $('Parse DexScreener').first().json; } catch(e) {} }
if (!tokenData) { tokenData = $('Extract Input').item.json; }
let fund = '', social = '';
try { fund = items[0].json.choices[0].message.content || ''; } catch(e) { fund = 'Unavailable'; }
try { social = items[1].json.choices[0].message.content || ''; } catch(e) { social = 'Unavailable'; }
return [{ json: { ...tokenData, fundamentals_research: fund, social_research: social } }];

// Stage 2: 4-LLM analysis prompt (full Apex Game Theorist prompt with all output fields)
const d = $input.all()[0].json;
const prompt = `You are the Apex Crypto Game Theorist...

TOKEN: ${d.ticker} (${d.name})
Chain: ${d.chain}, Price: $${d.price}, MCap: $${d.market_cap}, FDV: $${d.fdv}
Volume 24h: $${d.volume_24h}, DEX Liq: $${d.dex_liquidity_usd}

FUNDAMENTALS:
${d.fundamentals_research}

SOCIAL:
${d.social_research}

Output ALL fields in key: value format (one per line, no markdown).`;
const models = { gpt: 'openai/gpt-4o', gemini: 'google/gemini-2.5-pro', claude: 'anthropic/claude-sonnet-4-5', grok: 'x-ai/grok-3' };
const mk = (m) => ({ model: m, messages: [{ role: 'user', content: prompt }], max_tokens: 4000 });
return [{ json: { gptBody: mk(models.gpt), geminiBody: mk(models.gemini), claudeBody: mk(models.claude), grokBody: mk(models.grok) } }];

// Stage 3: Deliberation - each model reviews own + 3 others
const items = $input.all();
const names = ['GPT', 'Gemini', 'Claude', 'Grok'];
const ids = ['openai/gpt-4o', 'google/gemini-2.5-pro', 'anthropic/claude-sonnet-4-5', 'x-ai/grok-3'];
const s2 = [];
for (let i = 0; i < 4; i++) { try { s2.push(items[i].json.choices[0].message.content); } catch(e) { s2.push('Unavailable'); } }
let ticker = '';
try { ticker = $('Parse CoinGecko').first().json.ticker; } catch(e) {}
if (!ticker) try { ticker = $('Parse DexScreener').first().json.ticker; } catch(e) {}
const bp = (mi) => { const others = [0,1,2,3].filter(i => i !== mi).map(i => `--- ${names[i]} ---\n${s2[i]}`).join('\n'); return `Review your ${ticker} analysis vs 3 others.\nYOURS:\n${s2[mi]}\nOTHERS:\n${others}\nRevise if evidence warrants. Output key: value format.`; };
return [{ json: { gptBody: { model: ids[0], messages: [{ role: 'user', content: bp(0) }], max_tokens: 4000 }, geminiBody: { model: ids[1], messages: [{ role: 'user', content: bp(1) }], max_tokens: 4000 }, claudeBody: { model: ids[2], messages: [{ role: 'user', content: bp(2) }], max_tokens: 4000 }, grokBody: { model: ids[3], messages: [{ role: 'user', content: bp(3) }], max_tokens: 4000 } } }];

// Stage 4: Consensus aggregation
const items = $input.all();
const s3 = [];
for (let i = 0; i < 4; i++) { try { s3.push(items[i].json.choices[0].message.content); } catch(e) { s3.push('Unavailable'); } }
let td = {};
try { td = $('Parse CoinGecko').first().json; } catch(e) {}
if (!td || !td.ticker) try { td = $('Parse DexScreener').first().json; } catch(e) {}
const prompt = `Final Consensus Aggregator for ${td.ticker || 'token'}.
Price: $${td.price}, MCap: $${td.market_cap}, FDV: $${td.fdv}

--- GPT ---
${s3[0]}
--- Gemini ---
${s3[1]}
--- Claude ---
${s3[2]}
--- Grok ---
${s3[3]}

Aggregate: median scores, majority vote categories, synthesize thesis/catalysts/risks.
Consensus spread: <=10 HIGH, <=25 MIXED, <=40 LOW, >40 CONFLICTED.
Output key: value format. Include gpt_score, gemini_score, claude_score, grok_score.`;
return [{ json: { requestBody: { model: 'anthropic/claude-sonnet-4-5', messages: [{ role: 'user', content: prompt }], max_tokens: 4000 } } }];

// Format result for Nash Satoshi webhook callback
const run_id = $('Extract Input').item.json.run_id || '';
const resp = $input.all()[0].json;
let result = '';
try { result = resp.choices[0].message.content || ''; } catch(e) { result = JSON.stringify(resp); }
return [{ json: { webhookBody: { run_id, state: 'DONE', outputs: { analysis_result: result } } } }];

// Build failure webhook body
let run_id = '';
try { run_id = $('Extract Input').item.json.run_id || ''; } catch(e) { run_id = 'unknown'; }
return [{ json: { webhookBody: { run_id, state: 'FAILED', outputs: {} } } }];
